	// ------------------------------------------------------------------
	// Kernel 3: ANALYTICS query 11 — predicate selectivity profile:
	// SELECT ?p COUNT(*) COUNT(DISTINCT ?s) COUNT(DISTINCT ?o) GROUP BY ?p.
	// ------------------------------------------------------------------

