	/**
	 * Applies the query's ORDER BY DESC(?statements) ?p (IRI string order) and renders canonical row strings for parity
	 * comparison and blackhole consumption.
	 */
	public static List<String> formatPredicateSelectivity(long[][] rows, NativeLmdbQuerySource source) {
		String[] predStrings = new String[rows.length];
		Integer[] order = new Integer[rows.length];
		for (int i = 0; i < rows.length; i++) {
			predStrings[i] = source.lazyValue(rows[i][0]).stringValue();
			order[i] = i;
		}
		Arrays.sort(order, (x, y) -> {
			int byStatements = Long.compare(rows[y][1], rows[x][1]);
			if (byStatements != 0) {
				return byStatements;
			}
			return predStrings[x].compareTo(predStrings[y]);
		});
		List<String> lines = new ArrayList<>(rows.length);
		for (int i : order) {
			lines.add(predStrings[i] + "|" + rows[i][1] + "|" + rows[i][2] + "|" + rows[i][3]);
		}
		return lines;
	}

	// ------------------------------------------------------------------
	// Minimal primitive collections, written the way generated code would
	// use them (no boxing, open addressing, power-of-two tables).
	// ------------------------------------------------------------------

	static final class LongHashSet {
		private long[] keys;
		private boolean hasZero;
		private int size;
		private int mask;

		LongHashSet(int expectedCapacity) {
			int capacity = Integer.highestOneBit(Math.max(16, expectedCapacity * 2 - 1)) << 1;
			keys = new long[capacity];
			mask = capacity - 1;
		}

		boolean add(long key) {
			if (key == 0L) {
				if (hasZero) {
					return false;
				}
				hasZero = true;
				size++;
				return true;
			}
			int slot = mix(key) & mask;
			while (true) {
				long existing = keys[slot];
				if (existing == 0L) {
					keys[slot] = key;
					if (++size * 2 > keys.length) {
						grow();
					}
					return true;
				}
				if (existing == key) {
					return false;
				}
				slot = (slot + 1) & mask;
			}
		}

		int size() {
			return size;
		}

		long[] toArray() {
			long[] result = new long[size];
			int out = 0;
			if (hasZero) {
				result[out++] = 0L;
			}
			for (long key : keys) {
				if (key != 0L) {
					result[out++] = key;
				}
			}
			Arrays.sort(result);
			return result;
		}

		private void grow() {
			long[] old = keys;
			keys = new long[old.length << 1];
			mask = keys.length - 1;
			for (long key : old) {
				if (key != 0L) {
					int slot = mix(key) & mask;
					while (keys[slot] != 0L) {
						slot = (slot + 1) & mask;
					}
					keys[slot] = key;
				}
			}
		}

		private static int mix(long key) {
			long h = key * 0x9E3779B97F4A7C15L;
			return (int) (h ^ (h >>> 32));
		}
	}

	static final class LongLongMap {
		private long[] keys;
		private long[] values;
		private long zeroValue;
		private boolean hasZero;
		private int size;
		private int mask;

		LongLongMap(int expectedCapacity) {
			int capacity = Integer.highestOneBit(Math.max(16, expectedCapacity * 2 - 1)) << 1;
			keys = new long[capacity];
			values = new long[capacity];
			mask = capacity - 1;
		}

		void increment(long key) {
			if (key == 0L) {
				hasZero = true;
				zeroValue++;
				return;
			}
			int slot = LongHashSet.mix(key) & mask;
			while (true) {
				long existing = keys[slot];
				if (existing == 0L) {
					keys[slot] = key;
					values[slot] = 1L;
					if (++size * 2 > keys.length) {
						grow();
					}
					return;
				}
				if (existing == key) {
					values[slot]++;
					return;
				}
				slot = (slot + 1) & mask;
			}
		}

		long get(long key) {
			if (key == 0L) {
				return hasZero ? zeroValue : 0L;
			}
			int slot = LongHashSet.mix(key) & mask;
			while (true) {
				long existing = keys[slot];
				if (existing == 0L) {
					return 0L;
				}
				if (existing == key) {
					return values[slot];
				}
				slot = (slot + 1) & mask;
			}
		}

		long[] keys() {
			long[] result = new long[size + (hasZero ? 1 : 0)];
			int out = 0;
			if (hasZero) {
				result[out++] = 0L;
			}
			for (long key : keys) {
				if (key != 0L) {
					result[out++] = key;
				}
			}
			Arrays.sort(result);
			return result;
		}

		private void grow() {
			long[] oldKeys = keys;
			long[] oldValues = values;
			keys = new long[oldKeys.length << 1];
			values = new long[keys.length];
			mask = keys.length - 1;
			for (int i = 0; i < oldKeys.length; i++) {
				long key = oldKeys[i];
				if (key != 0L) {
					int slot = LongHashSet.mix(key) & mask;
					while (keys[slot] != 0L) {
						slot = (slot + 1) & mask;
					}
					keys[slot] = key;
					values[slot] = oldValues[i];
				}
			}
		}
	}
